"""Evaluate regression predictions generated by `mmw-predict --json`."""

from __future__ import annotations

import argparse
import csv
import json
import re
from collections.abc import Sequence
from pathlib import Path
from typing import Any

import matplotlib.pyplot as plt
import numpy as np

DEFAULT_FLAT_LABEL_REGEX = r"^(?P<label>.+)_(?P<index>\d+)\.bin$"


def _to_float(raw: object) -> float | None:
    if raw is None:
        return None
    try:
        return float(raw)
    except (TypeError, ValueError):
        return None


def _infer_label(capture_path: Path, label_regex: re.Pattern[str]) -> str | None:
    match = label_regex.match(capture_path.name)
    if match is not None:
        label = match.groupdict().get("label")
        if label:
            return str(label)

    parent = capture_path.parent.name.strip()
    if parent:
        return parent
    return None


def _regression_metrics(y_true: np.ndarray, y_pred: np.ndarray) -> dict[str, float]:
    if y_true.size == 0:
        return {
            "mae": float("nan"),
            "rmse": float("nan"),
            "r2": float("nan"),
            "bias": float("nan"),
            "median_abs_error": float("nan"),
        }

    err = y_pred - y_true
    mae = float(np.mean(np.abs(err)))
    rmse = float(np.sqrt(np.mean(np.square(err))))
    bias = float(np.mean(err))
    med = float(np.median(np.abs(err)))

    sst = float(np.sum(np.square(y_true - np.mean(y_true))))
    if sst <= 1e-12:
        r2 = float("nan")
    else:
        sse = float(np.sum(np.square(err)))
        r2 = float(1.0 - (sse / sst))

    return {
        "mae": mae,
        "rmse": rmse,
        "r2": r2,
        "bias": bias,
        "median_abs_error": med,
    }


def _plot_true_vs_pred(
    y_true: np.ndarray,
    y_pred: np.ndarray,
    labels: list[str],
    *,
    output_path: Path,
    title: str,
) -> None:
    if y_true.size == 0:
        return

    unique_labels = sorted(set(labels))
    cmap = plt.get_cmap("tab10")

    fig, ax = plt.subplots(figsize=(7.8, 6.4))
    for idx, label in enumerate(unique_labels):
        mask = np.array([item == label for item in labels], dtype=bool)
        if not np.any(mask):
            continue
        ax.scatter(
            y_true[mask],
            y_pred[mask],
            s=24,
            alpha=0.8,
            label=label,
            color=cmap(idx % 10),
        )

    lo = float(min(np.min(y_true), np.min(y_pred)))
    hi = float(max(np.max(y_true), np.max(y_pred)))
    pad = max(0.05 * (hi - lo), 1e-3)
    lo -= pad
    hi += pad

    ax.plot([lo, hi], [lo, hi], "--", color="black", linewidth=1.1, label="ideal y=x")
    ax.set_xlim(lo, hi)
    ax.set_ylim(lo, hi)
    ax.set_xlabel("True value")
    ax.set_ylabel("Predicted value")
    ax.set_title(title)
    ax.grid(True, alpha=0.2)
    ax.legend(loc="best", fontsize=8)

    fig.tight_layout()
    output_path.parent.mkdir(parents=True, exist_ok=True)
    fig.savefig(output_path, dpi=180, bbox_inches="tight")
    plt.close(fig)


def _plot_error_hist(
    y_true: np.ndarray,
    y_pred: np.ndarray,
    *,
    output_path: Path,
    title: str,
) -> None:
    if y_true.size == 0:
        return

    err = y_pred - y_true
    fig, ax = plt.subplots(figsize=(7.8, 4.8))
    ax.hist(err, bins=24, color="#2563eb", alpha=0.85, edgecolor="white")
    ax.axvline(0.0, color="black", linestyle="--", linewidth=1.0)
    ax.set_xlabel("Prediction error (pred - true)")
    ax.set_ylabel("Count")
    ax.set_title(title)
    ax.grid(True, axis="y", alpha=0.2)

    fig.tight_layout()
    output_path.parent.mkdir(parents=True, exist_ok=True)
    fig.savefig(output_path, dpi=180, bbox_inches="tight")
    plt.close(fig)


def parse_args(argv: Sequence[str] | None = None) -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description=(
            "Evaluate regression predictions from `mmw-predict --json` against "
            "a label->target map using capture filenames/directories."
        )
    )
    parser.add_argument("--predictions-json", type=Path, required=True)
    parser.add_argument("--label-target-map", type=Path, required=True)
    parser.add_argument("--out-json", type=Path, default=None)
    parser.add_argument("--out-csv", type=Path, default=None)
    parser.add_argument("--none-label", default="none")
    parser.add_argument("--flat-label-regex", default=DEFAULT_FLAT_LABEL_REGEX)
    parser.add_argument("--plots", action="store_true")
    parser.add_argument("--out-dir", type=Path, default=None)
    return parser.parse_args(argv)


def main(argv: Sequence[str] | None = None) -> int:
    args = parse_args(argv)
    label_regex = re.compile(str(args.flat_label_regex))

    if args.out_json is None:
        args.out_json = args.predictions_json.with_name(
            f"{args.predictions_json.stem}_evaluation.json"
        )
    if args.out_csv is None:
        args.out_csv = args.predictions_json.with_name(
            f"{args.predictions_json.stem}_per_label.csv"
        )
    if args.out_dir is None:
        args.out_dir = args.out_json.parent

    raw_predictions = json.loads(args.predictions_json.read_text(encoding="utf-8"))
    if not isinstance(raw_predictions, list):
        raise RuntimeError("--predictions-json must contain a JSON list.")

    raw_target_map = json.loads(args.label_target_map.read_text(encoding="utf-8"))
    if not isinstance(raw_target_map, dict):
        raise RuntimeError("--label-target-map must contain a JSON object.")
    target_map = {str(key): float(value) for key, value in raw_target_map.items()}

    y_true_list: list[float] = []
    y_pred_list: list[float] = []
    label_list: list[str] = []
    input_list: list[str] = []

    skipped_non_regression = 0
    skipped_missing_input = 0
    skipped_missing_label = 0
    skipped_missing_target = 0
    skipped_missing_prediction = 0

    for entry in raw_predictions:
        if not isinstance(entry, dict):
            continue

        task = str(entry.get("task", ""))
        if task and task != "regression":
            skipped_non_regression += 1
            continue

        input_raw = entry.get("input")
        if input_raw is None:
            skipped_missing_input += 1
            continue

        capture_path = Path(str(input_raw))
        label = _infer_label(capture_path, label_regex)
        if label is None:
            skipped_missing_label += 1
            continue

        target_value = target_map.get(label)
        if target_value is None:
            skipped_missing_target += 1
            continue

        pred_value = _to_float(entry.get("value"))
        if pred_value is None:
            skipped_missing_prediction += 1
            continue

        y_true_list.append(float(target_value))
        y_pred_list.append(float(pred_value))
        label_list.append(label)
        input_list.append(str(capture_path))

    y_true = np.asarray(y_true_list, dtype=np.float32)
    y_pred = np.asarray(y_pred_list, dtype=np.float32)

    metrics_all = _regression_metrics(y_true, y_pred)

    non_none_mask = np.array([label != str(args.none_label) for label in label_list], dtype=bool)
    y_true_non_none = y_true[non_none_mask]
    y_pred_non_none = y_pred[non_none_mask]
    labels_non_none = [label for label in label_list if label != str(args.none_label)]
    metrics_without_none = _regression_metrics(y_true_non_none, y_pred_non_none)

    per_label_rows: list[dict[str, object]] = []
    for label in sorted(set(label_list)):
        mask = np.array([item == label for item in label_list], dtype=bool)
        label_metrics = _regression_metrics(y_true[mask], y_pred[mask])
        per_label_rows.append(
            {
                "label": label,
                "count": int(np.sum(mask)),
                "mae": float(label_metrics["mae"]),
                "rmse": float(label_metrics["rmse"]),
                "r2": float(label_metrics["r2"]),
                "bias": float(label_metrics["bias"]),
                "median_abs_error": float(label_metrics["median_abs_error"]),
            }
        )

    args.out_csv.parent.mkdir(parents=True, exist_ok=True)
    with args.out_csv.open("w", encoding="utf-8", newline="") as handle:
        writer = csv.DictWriter(
            handle,
            fieldnames=["label", "count", "mae", "rmse", "r2", "bias", "median_abs_error"],
        )
        writer.writeheader()
        for row in per_label_rows:
            writer.writerow(row)

    artifacts: dict[str, str] = {"per_label_csv": str(args.out_csv.resolve())}
    if args.plots:
        args.out_dir.mkdir(parents=True, exist_ok=True)
        stem = args.out_json.stem
        scatter_all = args.out_dir / f"{stem}_scatter_all.png"
        hist_all = args.out_dir / f"{stem}_error_hist_all.png"
        scatter_non_none = args.out_dir / f"{stem}_scatter_without_none.png"
        hist_non_none = args.out_dir / f"{stem}_error_hist_without_none.png"

        _plot_true_vs_pred(
            y_true,
            y_pred,
            label_list,
            output_path=scatter_all,
            title="Regression: True vs Predicted (All Samples)",
        )
        _plot_error_hist(
            y_true,
            y_pred,
            output_path=hist_all,
            title="Regression Error Histogram (All Samples)",
        )
        _plot_true_vs_pred(
            y_true_non_none,
            y_pred_non_none,
            labels_non_none,
            output_path=scatter_non_none,
            title=f"Regression: True vs Predicted (Without {args.none_label!r})",
        )
        _plot_error_hist(
            y_true_non_none,
            y_pred_non_none,
            output_path=hist_non_none,
            title=f"Regression Error Histogram (Without {args.none_label!r})",
        )

        artifacts.update(
            {
                "scatter_all": str(scatter_all.resolve()),
                "error_hist_all": str(hist_all.resolve()),
                "scatter_without_none": str(scatter_non_none.resolve()),
                "error_hist_without_none": str(hist_non_none.resolve()),
            }
        )

    summary = {
        "predictions_json": str(args.predictions_json.resolve()),
        "label_target_map": str(args.label_target_map.resolve()),
        "none_label": str(args.none_label),
        "counts": {
            "raw_records": len(raw_predictions),
            "used_records": int(y_true.size),
            "used_without_none": int(y_true_non_none.size),
            "skipped_non_regression": int(skipped_non_regression),
            "skipped_missing_input": int(skipped_missing_input),
            "skipped_missing_label": int(skipped_missing_label),
            "skipped_missing_target": int(skipped_missing_target),
            "skipped_missing_prediction": int(skipped_missing_prediction),
        },
        "metrics_all": metrics_all,
        "metrics_without_none": metrics_without_none,
        "artifacts": artifacts,
    }

    args.out_json.parent.mkdir(parents=True, exist_ok=True)
    args.out_json.write_text(json.dumps(summary, indent=2), encoding="utf-8")

    print(
        "Regression metrics (all): "
        f"MAE={metrics_all['mae']:.4f} RMSE={metrics_all['rmse']:.4f} R2={metrics_all['r2']:.4f}"
    )
    print(
        f"Regression metrics (without {args.none_label!r}): "
        f"MAE={metrics_without_none['mae']:.4f} "
        f"RMSE={metrics_without_none['rmse']:.4f} "
        f"R2={metrics_without_none['r2']:.4f}"
    )
    print(f"Saved regression evaluation summary: {args.out_json}")
    print(f"Saved per-label regression CSV: {args.out_csv}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
